class BookMyShow {
public:
    vector<vector<bool>> seats;
    BookMyShow(int n, int m) {
        seats.resize(n, vector<bool>(m, false));
    }

    vector<int> gather(int k, int maxRow) {
        for (int i = 0; i <= maxRow; i++) {
            bool valid = true;
            for (int j = 0; j < k; j++) {
                if (j + k > seats[i].size() || seats[i][j]) {
                    valid = false;
                    break;
                }
            }
            if (valid) {
                for (int j = 0; j < k; j++) {
                    seats[i][j] = true;
                }
                return {i, 0};
            }
        }
        return {};
    }

    bool scatter(int k, int maxRow) {
        int allocated = 0;
        for (int i = 0; i <= maxRow; i++) {
            for (int j = 0; j < seats[i].size(); j++) {
                if (!seats[i][j]) {
                    seats[i][j] = true;
                    allocated++;
                    if (allocated == k) {
                        return true;
                    }
                }
            }
        }
        return false;
    }
};

